 1	import React, { FC, useState } from 'react';
 2	
 3	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
 5	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 6	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import {
 9	  Alert,
10	  AlertVariant,
11	  Checkbox,
12	  ModalVariant,
13	  Stack,
14	  StackItem,
15	} from '@patternfly/react-core';
16	
17	import { createRDPService } from '../utils/utils';
18	
19	type RDPServiceModalProps = {
20	  isOpen: boolean;
21	  onClose: () => void;
22	  vm: V1VirtualMachine;
23	  vmi: V1VirtualMachineInstance;
24	};
25	
26	const RDPServiceModal: FC<RDPServiceModalProps> = ({ isOpen, onClose, vm, vmi }) => {
27	  const { t } = useKubevirtTranslation();
28	  const [isChecked, setChecked] = useState<boolean>(false);
29	
30	  return (
31	    <TabModal
32	      headerText={t('RDP Service')}
33	      isDisabled={!isChecked}
34	      isOpen={isOpen}
35	      modalVariant={ModalVariant.medium}
36	      onClose={onClose}
37	      onSubmit={() => createRDPService(vm, vmi)}
38	    >
39	      <Stack hasGutter>
40	        <StackItem>
41	          <Checkbox
42	            className="kv-rdp-service-checkbox--main"
43	            data-checked-state={isChecked}
44	            id="rdp-service-checkbox"
45	            isChecked={isChecked}
46	            label={t('Expose RDP Service')}
47	            onChange={(_event, val) => setChecked(val)}
48	          />
49	        </StackItem>
50	        <StackItem>
51	          <Alert isInline title={t('Node port')} variant={AlertVariant.info}>
52	            <div>
53	              {t('RDP Service is using a node port. Node port requires additional port resources.')}
54	              <div>
55	                <ExternalLink href={documentationURL.NODEPORTS} text={t('Learn more')} />
56	              </div>
57	            </div>
58	          </Alert>
59	        </StackItem>
60	      </Stack>
61	    </TabModal>
62	  );
63	};
64	
65	export default RDPServiceModal;

